UPDATE resources
SET url_pattern=#{urlPattern}, http_method=#{httpMethod}, descr=#{descr}, sort_order=#{sortOrder},
    updated_at=#{updatedAt}, updated_by=#{updatedBy}
WHERE id=#{id}

UPDATE menus
SET parent_id=#{parentId}, name=#{name}, url=#{url}, icon=#{icon}, sort_order=#{sortOrder},
    updated_at=#{updatedAt}, updated_by=#{updatedBy}
WHERE id=#{id}
